function solve(m, n, waitCost) {
    const INF = Infinity;
    const dp = Array(m).fill().map(() => Array(n).fill().map(() => Array(2).fill(INF)));
    dp[0][0][1] = 1;
    const heap = [];
    heap.push([1, 0, 0, 1]);

    function push(heap, cost, i, j, p) {
        heap.push([cost, i, j, p]);
        let idx = heap.length - 1;
        while (idx > 0) {
            const parent = Math.floor((idx - 1) / 2);
            if (heap[idx][0] < heap[parent][0]) {
                [heap[idx], heap[parent]] = [heap[parent], heap[idx]];
                idx = parent;
            } else {
                break;
            }
        }
    }

    function pop(heap) {
        if (heap.length === 0) return null;
        const min = heap[0];
        heap[0] = heap[heap.length - 1];
        heap.pop();
        let idx = 0;
        while (true) {
            const left = 2 * idx + 1;
            const right = 2 * idx + 2;
            let smallest = idx;
            if (left < heap.length && heap[left][0] < heap[smallest][0]) {
                smallest = left;
            }
            if (right < heap.length && heap[right][0] < heap[smallest][0]) {
                smallest = right;
            }
            if (smallest === idx) break;
            [heap[idx], heap[smallest]] = [heap[smallest], heap[idx]];
            idx = smallest;
        }
        return min;
    }

    while (heap.length > 0) {
        const [cost, i, j, p] = pop(heap);
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dp[i][j][p]) {
            continue;
        }
        if (p === 1) {
            const directions = [[0, 1], [1, 0]];
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const entryCost = (ni + 1) * (nj + 1);
                    const newCost = cost + entryCost;
                    if (newCost < dp[ni][nj][0]) {
                        dp[ni][nj][0] = newCost;
                        push(heap, newCost, ni, nj, 0);
                    }
                }
            }
        } else {
            const waitCostVal = waitCost[i][j];
            const newCost = cost + waitCostVal;
            if (newCost < dp[i][j][1]) {
                dp[i][j][1] = newCost;
                push(heap, newCost, i, j, 1);
            }
        }
    }
    return -1;
}
