function solve(m, n, waitCost) {
    const INF = Infinity;
    const dp = Array(m).fill().map(() => Array(n).fill().map(() => Array(2).fill(INF)));
    dp[0][0][1] = 1;
    const pq = new PriorityQueue();

    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.heap.sort((a, b) => a[0] - b[0]);
        }
        pop() {
            return this.heap.shift();
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    pq.push([1, 0, 0, 1]);

    while (!pq.isEmpty()) {
        const [cost, i, j, p] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dp[i][j][p]) {
            continue;
        }
        if (p === 1) {
            const directions = [[0, 1], [1, 0]];
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const entryCost = (ni + 1) * (nj + 1);
                    const newCost = cost + entryCost;
                    if (newCost < dp[ni][nj][0]) {
                        dp[ni][nj][0] = newCost;
                        pq.push([newCost, ni, nj, 0]);
                    }
                }
            }
        } else {
            const waitCostValue = waitCost[i][j];
            const newCost = cost + waitCostValue;
            if (newCost < dp[i][j][1]) {
                dp[i][j][1] = newCost;
                pq.push([newCost, i, j, 1]);
            }
        }
    }
    return -1;
}
